import { ref } from 'vue'
import { checkoutApi } from '@/api/endpoints/checkout'

export interface CartItem {
  session_id: string
  session_title: string
  unit_price: number
  quantity: number
}

export interface AppliedPromotion {
  promotion_id: string
  promotion_name: string
  promotion_type: string
  discount_amount: number
  explanation: string  // "Applied 'Buy-One-Get-One' because you have 2 workshops"
}

export interface BestOffer {
  subtotal: number
  discount_total: number
  total: number
  applied_promotions: AppliedPromotion[]
}

export interface Order {
  id: string
  learner_id: string
  status: 'pending' | 'paid' | 'cancelled' | 'refunded'
  subtotal: number
  discount_total: number
  total: number
  currency: string
  applied_promotions: AppliedPromotion[]
  items: CartItem[]
  created_at: string
  paid_at: string | null
  expires_at: string
}

export const useCheckoutStore = defineStore('checkout', () => {
  const cartId = ref<string | null>(null)
  const cartItems = ref<CartItem[]>([])
  const bestOffer = ref<BestOffer | null>(null)
  const order = ref<Order | null>(null)
  const loading = ref(false)
  const bestOfferLoading = ref(false)

  async function createCart(items: { session_id: string; quantity: number }[]) {
    loading.value = true
    try {
      const res = await checkoutApi.createCart(items)
      cartId.value = res.id
      cartItems.value = res.items
      // Immediately calculate best offer after cart creation
      await fetchBestOffer(res.id)
      return res
    } finally {
      loading.value = false
    }
  }

  async function applyPromo(code: string) {
    if (!cartId.value) return
    bestOfferLoading.value = true
    try {
      await checkoutApi.applyPromo(cartId.value, code)
      await fetchBestOffer(cartId.value)
    } finally {
      bestOfferLoading.value = false
    }
  }

  async function fetchBestOffer(id?: string) {
    const cid = id ?? cartId.value
    if (!cid) return
    bestOfferLoading.value = true
    try {
      bestOffer.value = await checkoutApi.getBestOffer(cid)
    } finally {
      bestOfferLoading.value = false
    }
  }

  async function confirmCart() {
    if (!cartId.value) throw new Error('No active cart')
    loading.value = true
    try {
      order.value = await checkoutApi.confirmCart(cartId.value)
      return order.value
    } finally {
      loading.value = false
    }
  }

  async function fetchOrder(id: string) {
    order.value = await checkoutApi.getOrder(id)
    return order.value
  }

  async function cancelOrder(id: string) {
    order.value = await checkoutApi.cancelOrder(id)
    return order.value
  }

  function clearCart() {
    cartId.value = null
    cartItems.value = []
    bestOffer.value = null
  }

  return {
    cartId, cartItems, bestOffer, order, loading, bestOfferLoading,
    createCart, applyPromo, fetchBestOffer, confirmCart, fetchOrder, cancelOrder, clearCart,
  }
})
"}

