{"file_path": "C:/Users/bita/Work/EaglePointAI/Full-stack/Meridian Training Operations system/repo/frontend/src/api/client.ts", "content": "import axios, { type AxiosRequestConfig } from 'axios'

const client = axios.create({
  baseURL: '/',
  headers: { 'Content-Type': 'application/json' },
})

// Attach Bearer token from auth store on every request
client.interceptors.request.use(config => {
  // Import lazily to avoid circular dependency at module load time
  const { useAuthStore } = require('@/stores/auth')
  const auth = useAuthStore()
  if (auth.accessToken) {
    config.headers.Authorization = `Bearer ${auth.accessToken}`
  }
  return config
})

// Queue for requests waiting on token refresh
let refreshing = false
let waitQueue: Array<{ resolve: (token: string) => void; reject: (e: unknown) => void }> = []

function processQueue(error: unknown, token: string | null) {
  waitQueue.forEach(p => error ? p.reject(error) : p.resolve(token!))
  waitQueue = []
}

client.interceptors.response.use(
  res => res,
  async error => {
    const original: AxiosRequestConfig & { _retry?: boolean } = error.config
    const status = error.response?.status

    if (status === 401 && !original._retry && !original.url?.includes('/api/auth/refresh')) {
      if (refreshing) {
        return new Promise((resolve, reject) => {
          waitQueue.push({
            resolve: token => {
              original.headers = { ...original.headers, Authorization: `Bearer ${token}` }
              resolve(client(original))
            },
            reject,
          })
        })
      }

      original._retry = true
      refreshing = true

      try {
        const { useAuthStore } = require('@/stores/auth')
        const auth = useAuthStore()
        const newToken = await auth.refresh()
        processQueue(null, newToken)
        original.headers = { ...original.headers, Authorization: `Bearer ${newToken}` }
        return client(original)
      } catch (refreshError) {
        processQueue(refreshError, null)
        const { useAuthStore } = require('@/stores/auth')
        const auth = useAuthStore()
        await auth.logout()
        window.location.href = '/login'
        return Promise.reject(refreshError)
      } finally {
        refreshing = false
      }
    }

    // Normalize error shape
    const message = error.response?.data?.detail ?? error.response?.data?.message ?? error.message
    const normalized = Object.assign(new Error(message), {
      statusCode: status,
      errors: error.response?.data?.errors,
    })
    return Promise.reject(normalized)
  }
)

export default client
"}

