      :session="selectedSession"
      :tz="tz"
      @close="selectedSession = null"
      @book="/* handled in learner view */"
      @live-room="/* handled in learner view */"
      @roster="router.push(`${prefix}/sessions/${$event.id}`)"
    />
  </AppLayout>
</template>
