import { ref, onMounted, computed, onUnmounted } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { useSessionsStore } from '@/stores/sessions'
import { useBookingsStore } from '@/stores/bookings'
import { useAuthStore } from '@/stores/auth'
import { useUiStore } from '@/stores/ui'
import { sessionsApi } from '@/api/endpoints/sessions'
import { formatInTimeZone } from 'date-fns-tz'
import { parseISO, differenceInSeconds, isPast } from 'date-fns'
import AppLayout from '@/layouts/AppLayout.vue'
import StatusBadge from '@/components/shared/StatusBadge.vue'
import LoadingSpinner from '@/components/shared/LoadingSpinner.vue'
import LiveRoomModal from '@/components/live/LiveRoomModal.vue'

const route = useRoute()
const router = useRouter()
const sessions = useSessionsStore()
const bookings = useBookingsStore()
const auth = useAuthStore()
const ui = useUiStore()

const sessionId = route.params.id as string
const activeTab = ref<'info' | 'roster' | 'attendance' | 'replay'>('info')

// Replay state
const replayLoading = ref(false)
const replayUrl = ref<string | null>(null)
const replayExpiresAt = ref<string | null>(null)  // ISO string of available_until
const replayExpired = ref(false)
const replayCountdown = ref('')
const showLiveRoom = ref(false)

let countdownInterval: ReturnType<typeof setInterval> | null = null

const tz = computed(() => auth.user?.tz ?? Intl.DateTimeFormat().resolvedOptions().timeZone)

onMounted(async () => {
  await sessions.fetchOne(sessionId)
})

onUnmounted(() => {
  if (countdownInterval) clearInterval(countdownInterval)
})

// ── Replay expiry logic (correction #3) ────────────────────────────────────
async function loadReplay() {
  replayLoading.value = true
  try {
    const data = await sessionsApi.getReplay(sessionId)
    replayExpiresAt.value = data.available_until

    if (isPast(parseISO(data.available_until))) {
      replayExpired.value = true
      return
    }

    replayUrl.value = data.presigned_url
    startCountdown(data.available_until)
  } catch (e: any) {
    if (e.statusCode === 403 || e.statusCode === 410) {
      replayExpired.value = true
    } else {
      ui.addToast(e.message ?? 'Failed to load replay', 'error')
    }
  } finally {
    replayLoading.value = false
  }
}

function startCountdown(expiresAt: string) {
  function update() {
    const secs = differenceInSeconds(parseISO(expiresAt), new Date())
    if (secs <= 0) {
      replayExpired.value = true
      replayUrl.value = null
      clearInterval(countdownInterval!)
      replayCountdown.value = ''
      return
    }
    const days = Math.floor(secs / 86400)
    const hrs = Math.floor((secs % 86400) / 3600)
    const mins = Math.floor((secs % 3600) / 60)
    replayCountdown.value = days > 0 ? `${days}d ${hrs}h remaining` : hrs > 0 ? `${hrs}h ${mins}m remaining` : `${mins}m remaining`
  }
  update()
  countdownInterval = setInterval(update, 60000)
}

function handleTabReplay() {
  activeTab.value = 'replay'
  if (!replayUrl.value && !replayExpired.value) loadReplay()
}

// ── Booking (learner) ────────────────────────────────────────────────────────
async function handleBook() {
  try {
    await bookings.create(sessionId)
    ui.addToast('Booked successfully!', 'success')
  } catch (e: any) {
    ui.addToast(e.message, 'error')
  }
}

const session = computed(() => sessions.currentSession)
</script>

<template>
  <AppLayout>
    <LoadingSpinner v-if="sessions.loading && !session" class="py-16" />

    <template v-else-if="session">
      <!-- Header -->
      <div class="flex items-start justify-between mb-6">
        <div>
          <h1 class="text-xl font-semibold text-foreground">{{ session.course_title }}</h1>
          <div class="flex items-center gap-2 mt-1">
            <StatusBadge :status="session.status" />
            <span class="text-sm text-muted-foreground">{{ session.location_name }} · {{ session.room_name }}</span>
          </div>
        </div>

        <!-- Actions for learner -->
