import { ref, onMounted, watch } from 'vue'
import { useRouter, useRoute } from 'vue-router'
import { useCheckoutStore } from '@/stores/checkout'
import { useUiStore } from '@/stores/ui'
import AppLayout from '@/layouts/AppLayout.vue'
import DiscountTraceability from '@/components/checkout/DiscountTraceability.vue'
import LoadingSpinner from '@/components/shared/LoadingSpinner.vue'

const router = useRouter()
const route = useRoute()
const checkout = useCheckoutStore()
const ui = useUiStore()

// Expect cart items passed via router state or query; for demo, use store
const promoCode = ref('')
const isConfirming = ref(false)

onMounted(async () => {
  // If cart already exists (created when user clicked "Book Now"), fetch best offer
  if (checkout.cartId) {
    await checkout.fetchBestOffer()
  }
})

// Correction #1: reactively re-fetch best offer whenever cartItems change
watch(() => checkout.cartItems.length, async () => {
  if (checkout.cartId) await checkout.fetchBestOffer()
})

async function applyPromo() {
  if (!promoCode.value.trim()) return
  try {
    await checkout.applyPromo(promoCode.value.trim())
    promoCode.value = ''
    ui.addToast('Promo applied', 'success')
  } catch (e: any) {
    ui.addToast(e.message ?? 'Invalid promo code', 'error')
  }
}

async function handleConfirm() {
  isConfirming.value = true
  try {
    const order = await checkout.confirmCart()
    ui.addToast('Order confirmed!', 'success')
    router.push(`/learner/orders/${order.id}`)
  } catch (e: any) {
    ui.addToast(e.message ?? 'Failed to confirm order', 'error')
  } finally {
    isConfirming.value = false
  }
}

function fmt(n: number) {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(n)
}
</script>

<template>
  <AppLayout>
    <div class="max-w-2xl mx-auto">
      <h1 class="text-xl font-semibold text-foreground mb-6">Checkout</h1>

      <div v-if="!checkout.cartId" class="text-center py-16 text-muted-foreground">
        Your cart is empty. <RouterLink to="/learner/sessions" class="text-primary hover:underline">Browse sessions</RouterLink>
      </div>

      <template v-else>
        <!-- Cart items -->
        <div class="bg-card border border-border rounded-lg p-5 mb-4">
          <h2 class="font-medium text-foreground mb-3">Sessions</h2>
          <div v-for="item in checkout.cartItems" :key="item.session_id" class="flex items-center justify-between py-2 border-b border-border last:border-0">
            <div>
              <p class="text-sm font-medium text-foreground">{{ item.session_title }}</p>
              <p class="text-xs text-muted-foreground">Qty: {{ item.quantity }}</p>
            </div>
            <span class="text-sm font-medium">{{ fmt(item.unit_price * item.quantity) }}</span>
          </div>
        </div>

        <!-- Promo code input -->
        <div class="bg-card border border-border rounded-lg p-5 mb-4">
          <h2 class="font-medium text-foreground mb-3">Promo Code</h2>
          <div class="flex gap-2">
            <input
              v-model="promoCode"
              type="text"
              placeholder="Enter code…"
              class="flex-1 px-3 py-2 rounded-md border border-border bg-background text-sm focus:outline-none focus:ring-2 focus:ring-ring"
              @keydown.enter.prevent="applyPromo"
            />
            <button @click="applyPromo" class="px-4 py-2 bg-secondary text-secondary-foreground rounded text-sm hover:bg-accent">
              Apply
            </button>
          </div>
        </div>

        <!-- Best-offer + discount traceability — correction #1 -->
        <div class="bg-card border border-border rounded-lg p-5 mb-6">
          <h2 class="font-medium text-foreground mb-3">Order Summary</h2>

          <LoadingSpinner v-if="checkout.bestOfferLoading" size="sm" class="py-4" />

          <DiscountTraceability
            v-else-if="checkout.bestOffer"
            :promotions="checkout.bestOffer.applied_promotions"
            :subtotal="checkout.bestOffer.subtotal"
            :discount-total="checkout.bestOffer.discount_total"
            :total="checkout.bestOffer.total"
          />
        </div>

        <!-- Confirm -->
        <button
          @click="handleConfirm"
          :disabled="isConfirming || checkout.bestOfferLoading"
