import { ref, onMounted } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { adminApi } from '@/api/endpoints/admin'
import { useUiStore } from '@/stores/ui'
import AppLayout from '@/layouts/AppLayout.vue'

const route = useRoute()
const router = useRouter()
const ui = useUiStore()
const editId = route.params.id as string | undefined
const isEdit = !!editId && editId !== 'new'

const form = ref({ username: '', role: 'learner', password: '', is_active: true })
const isSubmitting = ref(false)

onMounted(async () => {
  if (isEdit) {
    const u = await adminApi.getUser(editId!)
    Object.assign(form.value, u)
  }
})

async function handleSubmit() {
  isSubmitting.value = true
  try {
    if (isEdit) {
      await adminApi.updateUser(editId!, { role: form.value.role as any, is_active: form.value.is_active })
      ui.addToast('User updated', 'success')
    } else {
      await adminApi.createUser(form.value as any)
      ui.addToast('User created', 'success')
    }
    router.push('/admin/users')
  } catch (e: any) { ui.addToast(e.message, 'error') }
  finally { isSubmitting.value = false }
}
</script>

<template>
