const mockBestOffer = {
  subtotal: 100,
  discount_total: 15,
  total: 85,
  applied_promotions: [
    {
      promotion_id: 'p1',
      promotion_name: '10% off',
      promotion_type: 'pct_off',
      discount_amount: 10,
      explanation: "Applied '10% off' because workshop qualifies",
