    vi.clearAllMocks()
  })

  it('createCart fetches best offer immediately — correction #1', async () => {
    vi.mocked(checkoutApi.createCart).mockResolvedValue({ id: 'cart-1', items: [{ session_id: 's1', session_title: 'Test', unit_price: 100, quantity: 1 }] })
    vi.mocked(checkoutApi.getBestOffer).mockResolvedValue(mockBestOffer)

    const store = useCheckoutStore()
    await store.createCart([{ session_id: 's1', quantity: 1 }])

    // Best offer must be fetched immediately after cart creation
    expect(checkoutApi.getBestOffer).toHaveBeenCalledWith('cart-1')
    expect(store.bestOffer).not.toBeNull()
    expect(store.bestOffer!.discount_total).toBe(15)
  })

  it('bestOffer applied_promotions contain explanation text', async () => {
