    await store.createCart([])

    expect(store.bestOffer!.applied_promotions[0].explanation).toContain('Applied')
    expect(store.bestOffer!.applied_promotions[1].explanation).toContain('bundle-group')
  })

  it('confirmCart transitions order', async () => {
    vi.mocked(checkoutApi.createCart).mockResolvedValue({ id: 'cart-1', items: [] })
    vi.mocked(checkoutApi.getBestOffer).mockResolvedValue(mockBestOffer)
    vi.mocked(checkoutApi.confirmCart).mockResolvedValue({ id: 'order-1', status: 'pending', subtotal: 100, discount_total: 15, total: 85, applied_promotions: mockBestOffer.applied_promotions, items: [], currency: 'USD', created_at: '', paid_at: null, expires_at: '' })

    const store = useCheckoutStore()
    store.cartId = 'cart-1'
    const order = await store.confirmCart()
    expect(order.id).toBe('order-1')
    expect(store.order!.status).toBe('pending')
  })
})
"}

